import { afterAll, beforeAll, beforeEach, describe, expect, test } from "bun:test";
import {
	DeveloperCostBreakdownSchema,
	DeveloperDetailsSchema,
	DeveloperErrorSchema,
	DeveloperFeatureUsageSchema,
	DeveloperProjectSchema,
	DeveloperSessionSchema,
	DeveloperSummarySchema,
	DeveloperTimelineSchema,
	DeveloperTrendDataPointSchema,
	DimensionAnalysisDataPointSchema,
	ErrorTrendDataPointSchema,
	InsightSchema,
	LearningEntrySchema,
	LearningsFeedStatsSchema,
	LearningsTrendDataPointSchema,
	ModelTokensTrendDataSchema,
	OverviewKPIsSchema,
	ProjectContributorSchema,
	ProjectCostBreakdownSchema,
	ProjectDetailDataSchema,
	ProjectErrorSchema,
	ProjectFeatureUsageSchema,
	ProjectInvestmentSchema,
	ProjectTrendDataPointSchema,
	ROIMetricsSchema,
	ROITrendSchema,
	RecurringErrorSchema,
	SessionAnalyticsSchema,
	SessionAnalyticsSummaryComparisonSchema,
	SessionAnalyticsSummarySchema,
	SessionDetailSchema,
	SuccessRateSchema,
	TeamSummaryComparisonSchema,
	UsageTrendDataSchema,
} from "@rudel/api-routes";
import {
	type TestServer,
	startTestServer,
} from "../../../cli/src/__tests__/helpers/bun-server.js";
import { z } from "zod";

// ── Constants ───────────────────────────────────────────────────────

const TEST_EMAIL = "analytics-test@rudel.ai";
const TEST_PASSWORD = "analytics-test-password-42";
const START_DATE = "2026-02-01";
const END_DATE = "2026-03-15";
const DAYS = 90;

// ── Shared state ────────────────────────────────────────────────────

let server: TestServer;
let token: string;
let userId: string;
let sessionList: Array<{ session_id: string; project_path: string }>;

// ── RPC helper ──────────────────────────────────────────────────────

async function rpc(path: string, input?: Record<string, unknown>) {
	const res = await fetch(`${server.baseUrl}/rpc/${path}`, {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			Authorization: `Bearer ${token}`,
		},
		body: JSON.stringify(input ? { json: input } : {}),
	});
	const data = await res.json();
	if (!res.ok) throw new Error(`RPC ${path}: ${res.status} ${JSON.stringify(data)}`);
	return (data as { json: unknown }).json;
}

// ── Setup / teardown ────────────────────────────────────────────────

beforeAll(async () => {
	if (!process.env.CLICKHOUSE_URL) {
		throw new Error("CLICKHOUSE_URL not set — skipping analytics integration tests");
	}

	server = await startTestServer();

	// Sign in as the pre-seeded test user
	const signInRes = await fetch(`${server.baseUrl}/api/auth/sign-in/email`, {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({ email: TEST_EMAIL, password: TEST_PASSWORD }),
	});
	if (!signInRes.ok) {
		const body = await signInRes.text();
		throw new Error(
			`Sign-in failed (${signInRes.status}): ${body}. ` +
				"Run: doppler run --project rudel --config ci -- bun scripts/seed-analytics-test-data.ts",
		);
	}

	// Extract token
	const signInData = (await signInRes.json()) as { token?: string };
	if (signInData.token) {
		token = signInData.token;
	} else {
		const cookies = signInRes.headers.getSetCookie();
		const sessionCookie = cookies
			.find((c) => c.startsWith("better-auth.session_token="))
			?.split("=")[1]
			?.split(";")[0];
		if (!sessionCookie) throw new Error("Could not extract token from sign-in response");
		token = sessionCookie;
	}

	// Get user ID
	const me = (await rpc("me")) as { id: string };
	userId = me.id;

	// Sanity check: verify analytics data exists
	const kpis = (await rpc("analytics/overview/kpis", {
		startDate: START_DATE,
		endDate: END_DATE,
	})) as { distinct_sessions: number };

	if (kpis.distinct_sessions < 5) {
		throw new Error(
			`Expected >= 5 sessions in analytics, got ${kpis.distinct_sessions}. ` +
				"Run: doppler run --project rudel --config ci -- bun scripts/seed-analytics-test-data.ts",
		);
	}

	// Cache session list for tests that need a session ID / project path
	sessionList = (await rpc("analytics/sessions/list", { days: DAYS })) as Array<{
		session_id: string;
		project_path: string;
	}>;
}, 120_000);

beforeEach(async () => {
	await server.ensureAlive();
});

afterAll(async () => {
	if (server) await server.stop();
});

// ── Overview ────────────────────────────────────────────────────────

describe("analytics/overview", () => {
	const dateRange = { startDate: START_DATE, endDate: END_DATE };

	test("kpis", async () => {
		const result = await rpc("analytics/overview/kpis", dateRange);
		const parsed = OverviewKPIsSchema.parse(result);
		expect(parsed.distinct_sessions).toBeGreaterThanOrEqual(5);
		expect(parsed.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("usageTrend", async () => {
		const result = await rpc("analytics/overview/usageTrend", dateRange);
		const parsed = z.array(UsageTrendDataSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("modelTokensTrend", async () => {
		const result = await rpc("analytics/overview/modelTokensTrend", dateRange);
		const parsed = z.array(ModelTokensTrendDataSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("insights", async () => {
		const result = await rpc("analytics/overview/insights", dateRange);
		const parsed = z.array(InsightSchema).parse(result);
		expect(Array.isArray(parsed)).toBe(true);
	}, 30_000);

	test("teamSummaryComparison", async () => {
		const result = await rpc("analytics/overview/teamSummaryComparison", dateRange);
		const parsed = TeamSummaryComparisonSchema.parse(result);
		expect(parsed.current.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("successRate", async () => {
		const result = await rpc("analytics/overview/successRate", dateRange);
		const parsed = SuccessRateSchema.parse(result);
		expect(parsed.current.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);
});

// ── Developers ──────────────────────────────────────────────────────

describe("analytics/developers", () => {
	test("list", async () => {
		const result = await rpc("analytics/developers/list", { days: DAYS });
		const parsed = z.array(DeveloperSummarySchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);

	test("details", async () => {
		const result = await rpc("analytics/developers/details", { days: DAYS, userId });
		const parsed = DeveloperDetailsSchema.parse(result);
		expect(parsed.user_id).toBe(userId);
		expect(parsed.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("sessions", async () => {
		const result = await rpc("analytics/developers/sessions", { days: DAYS, userId });
		const parsed = z.array(DeveloperSessionSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("projects", async () => {
		const result = await rpc("analytics/developers/projects", { days: DAYS, userId });
		const parsed = z.array(DeveloperProjectSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);

	test("timeline", async () => {
		const result = await rpc("analytics/developers/timeline", { days: DAYS, userId });
		const parsed = z.array(DeveloperTimelineSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("features", async () => {
		const result = await rpc("analytics/developers/features", { days: DAYS, userId });
		const parsed = DeveloperFeatureUsageSchema.parse(result);
		expect(parsed).toBeDefined();
	}, 30_000);

	test("errors", async () => {
		const result = await rpc("analytics/developers/errors", { days: DAYS, userId });
		const parsed = z.array(DeveloperErrorSchema).parse(result);
		expect(Array.isArray(parsed)).toBe(true);
	}, 30_000);

	test("trends", async () => {
		const result = await rpc("analytics/developers/trends", { days: DAYS });
		const parsed = z.array(DeveloperTrendDataPointSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);
});

// ── Projects ────────────────────────────────────────────────────────

describe("analytics/projects", () => {
	test("investment", async () => {
		const result = await rpc("analytics/projects/investment", { days: DAYS });
		const parsed = z.array(ProjectInvestmentSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);

	test("trends", async () => {
		const result = await rpc("analytics/projects/trends", { days: DAYS });
		const parsed = z.array(ProjectTrendDataPointSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("details", async () => {
		const projectPath = sessionList[0]?.project_path;
		expect(projectPath).toBeDefined();
		const result = await rpc("analytics/projects/details", { days: DAYS, projectPath });
		const parsed = ProjectDetailDataSchema.parse(result);
		expect(parsed.project_path).toBe(projectPath);
	}, 30_000);

	test("contributors", async () => {
		const projectPath = sessionList[0]?.project_path;
		expect(projectPath).toBeDefined();
		const result = await rpc("analytics/projects/contributors", { days: DAYS, projectPath });
		const parsed = z.array(ProjectContributorSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);

	test("features", async () => {
		const projectPath = sessionList[0]?.project_path;
		expect(projectPath).toBeDefined();
		const result = await rpc("analytics/projects/features", { days: DAYS, projectPath });
		const parsed = ProjectFeatureUsageSchema.parse(result);
		expect(parsed).toBeDefined();
	}, 30_000);

	test("errors", async () => {
		const projectPath = sessionList[0]?.project_path;
		expect(projectPath).toBeDefined();
		const result = await rpc("analytics/projects/errors", { days: DAYS, projectPath });
		const parsed = z.array(ProjectErrorSchema).parse(result);
		expect(Array.isArray(parsed)).toBe(true);
	}, 30_000);
});

// ── Sessions ────────────────────────────────────────────────────────

describe("analytics/sessions", () => {
	test("list", async () => {
		const result = await rpc("analytics/sessions/list", { days: DAYS });
		const parsed = z.array(SessionAnalyticsSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("summary", async () => {
		const result = await rpc("analytics/sessions/summary", { days: DAYS });
		const parsed = SessionAnalyticsSummarySchema.parse(result);
		expect(parsed.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("summaryComparison", async () => {
		const result = await rpc("analytics/sessions/summaryComparison", { days: DAYS });
		const parsed = SessionAnalyticsSummaryComparisonSchema.parse(result);
		expect(parsed.current.total_sessions).toBeGreaterThanOrEqual(5);
	}, 30_000);

	test("dimensionAnalysis", async () => {
		const result = await rpc("analytics/sessions/dimensionAnalysis", {
			days: DAYS,
			dimension: "project_path",
			metric: "session_count",
		});
		const parsed = z.array(DimensionAnalysisDataPointSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("detail", async () => {
		const sessionId = sessionList[0]?.session_id;
		expect(sessionId).toBeDefined();
		const result = await rpc("analytics/sessions/detail", { sessionId });
		const parsed = SessionDetailSchema.parse(result);
		expect(parsed.session_id).toBe(sessionId);
	}, 30_000);
});

// ── ROI ─────────────────────────────────────────────────────────────

describe("analytics/roi", () => {
	test("metrics", async () => {
		const result = await rpc("analytics/roi/metrics", { days: DAYS });
		const parsed = ROIMetricsSchema.parse(result);
		expect(parsed.total_sessions).toBeGreaterThanOrEqual(5);
