	test("trends", async () => {
		const result = await rpc("analytics/roi/trends", { days: DAYS });
		const parsed = z.array(ROITrendSchema).parse(result);
		expect(parsed.length).toBeGreaterThan(0);
	}, 30_000);

	test("breakdownDevelopers", async () => {
		const result = await rpc("analytics/roi/breakdownDevelopers", { days: DAYS });
		const parsed = z.array(DeveloperCostBreakdownSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);

	test("breakdownProjects", async () => {
		const result = await rpc("analytics/roi/breakdownProjects", { days: DAYS });
		const parsed = z.array(ProjectCostBreakdownSchema).parse(result);
		expect(parsed.length).toBeGreaterThanOrEqual(1);
	}, 30_000);
});

// ── Errors ──────────────────────────────────────────────────────────

describe("analytics/errors", () => {
	test("topRecurring", async () => {
		const result = await rpc("analytics/errors/topRecurring", {
			days: DAYS,
			minOccurrences: 1,
		});
		const parsed = z.array(RecurringErrorSchema).parse(result);
		expect(Array.isArray(parsed)).toBe(true);
	}, 30_000);

	test("trends", async () => {
		const result = await rpc("analytics/errors/trends", {
