import {
	type TestServer,
	startTestServer,
} from "../../../cli/src/__tests__/helpers/bun-server.js";

/** Parse an array response, validating each element against a Zod schema. */
function parseArray<T>(
	schema: { parse: (v: unknown) => T },
	data: unknown,
): T[] {
	if (!Array.isArray(data))
		throw new Error(`Expected array, got ${typeof data}`);
	return data.map((item) => schema.parse(item));
}

// ── Constants ───────────────────────────────────────────────────────

const TEST_EMAIL = "analytics-test@rudel.ai";
const TEST_PASSWORD = "analytics-test-password-42";
const START_DATE = "2026-02-01";
const END_DATE = "2026-03-15";
const DAYS = 90;

// ── Shared state ────────────────────────────────────────────────────

let server: TestServer;
let token: string;
let userId: string;
let sessionList: Array<{ session_id: string; project_path: string }>;

// ── RPC helper ──────────────────────────────────────────────────────

async function rpc(path: string, input?: Record<string, unknown>) {
	const res = await fetch(`${server.baseUrl}/rpc/${path}`, {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			Authorization: `Bearer ${token}`,
		},
		body: JSON.stringify(input ? { json: input } : {}),
	});
	const data = await res.json();
	if (!res.ok)
		throw new Error(`RPC ${path}: ${res.status} ${JSON.stringify(data)}`);
	return (data as { json: unknown }).json;
}

// ── Setup / teardown ────────────────────────────────────────────────

beforeAll(async () => {
