 97→export function escapeString(value: string): string {
 98→	return value.replace(/'/g, "\\'");
 99→}
100→
101→export function buildDateFilter(days: number, column = "session_date"): string {
102→	return `${column} >= now64(3) - INTERVAL ${Number(days)} DAY AND ${column} <= now64(3)`;
103→}
104→
105→export function buildAbsoluteDateFilter(
106→	startDate: string,
107→	endDate: string,
108→	column = "session_date",
109→): string {
110→	return `toDate(${column}) >= '${startDate}' AND toDate(${column}) <= '${endDate}'`;
111→}
112→
113→export async function queryClickhouse<T>(sql: string): Promise<T[]> {
114→	const ch = getClickhouse();
115→	return ch.query<T>(sql);
116→}
