 36→async function waitForRow(
 37→	sessionId: string,
 38→	timeoutMs = 30000,
 39→	intervalMs = 2000,
 40→): Promise<
 41→	Array<{
 42→		session_id: string;
 43→		project_path: string;
 44→		tag: string;
 45→		user_id: string;
 46→		organization_id: string;
 47→	}>
 48→> {
 49→	const start = Date.now();
 50→	while (Date.now() - start < timeoutMs) {
 51→		try {
 52→			const results = await executor.query<{
 53→				session_id: string;
 54→				project_path: string;
 55→				tag: string;
 56→				user_id: string;
 57→				organization_id: string;
 58→			}>(
 59→				`SELECT session_id, project_path, tag, user_id, organization_id FROM rudel.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
 60→			);
 61→			if (results.length > 0) return results;
 62→		} catch {
 63→			// Transient ClickHouse errors (e.g. S3 storage) - retry
 64→		}
 65→		await new Promise((r) => setTimeout(r, intervalMs));
 66→	}
 67→	return [];
 68→}
