 25→		clientId: process.env.GITHUB_CLIENT_ID,
 26→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 27→	};
 28→}
 29→
 30→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 31→const trustedOrigins = process.env.TRUSTED_ORIGINS
 32→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 33→	: ["http://localhost:4011"];
 34→
 35→const auth = createAuth(db, {
 36→	appURL,
 37→	secret: process.env.BETTER_AUTH_SECRET,
 38→	socialProviders,
 39→	trustedOrigins,
 40→	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 41→});
 42→
 43→const rpcHandler = new RPCHandler(router);
 44→
 45→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 46→const STATIC_DIR = join(
 47→	import.meta.dir,
 48→	"..",
 49→	process.env.STATIC_DIR ?? "public",
 50→);
 51→
 52→function corsHeaders(origin: string | null): Record<string, string> {
 53→	if (origin !== ALLOWED_ORIGIN) return {};
 54→	return {
 55→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 56→		"Access-Control-Allow-Credentials": "true",
 57→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 58→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 59→	};
 60→}
 61→
 62→const port = process.env.PORT ?? 4010;
 63→
 64→const server = Bun.serve({
 65→	port,
 66→	async fetch(request) {
 67→		const origin = request.headers.get("Origin");
 68→		const cors = corsHeaders(origin);
 69→
 70→		if (request.method === "OPTIONS") {
 71→			return new Response(null, { status: 204, headers: cors });
 72→		}
 73→
 74→		const url = new URL(request.url);
 75→
 76→		// Health check for Fly.io (must be GET-accessible)
 77→		if (url.pathname === "/health") {
 78→			return Response.json({ status: "ok", timestamp: Date.now() });
 79→		}
 80→
 81→		const requestId = crypto.randomUUID();
 82→		const start = performance.now();
 83→
 84→		return withContext(
 85→			{ requestId, method: request.method, path: url.pathname },
 86→			async () => {
 87→				const response = await handleRequest(request, url, cors);
 88→				const duration = Math.round(performance.now() - start);
 89→				logger.info("{method} {path} {status} {duration}ms", {
 90→					method: request.method,
 91→					path: url.pathname,
 92→					status: response.status,
 93→					duration,
 94→				});
 95→				return response;
 96→			},
 97→		);
 98→	},
 99→});
100→
101→async function handleRequest(
102→	request: Request,
103→	url: URL,
104→	cors: Record<string, string>,
105→): Promise<Response> {
106→	if (url.pathname === "/api/cli-token") {
107→		const session = await auth.api.getSession({
108→			headers: request.headers,
109→		});
110→		if (!session) {
111→			return new Response(JSON.stringify({ error: "Not authenticated" }), {
112→				status: 401,
113→				headers: { ...cors, "Content-Type": "application/json" },
114→			});
115→		}
116→		return new Response(JSON.stringify({ token: session.session.token }), {
117→			status: 200,
118→			headers: { ...cors, "Content-Type": "application/json" },
119→		});
120→	}
121→
122→	if (url.pathname.startsWith("/api/auth")) {
123→		const response = await auth.handler(request);
124→		for (const [key, value] of Object.entries(cors)) {
125→			response.headers.set(key, value);
126→		}
127→		return response;
128→	}
129→
130→	const { matched, response } = await rpcHandler.handle(request, {
131→		prefix: "/rpc",
132→		context: await getContext(request),
133→	});
134→
135→	if (matched) {
136→		if (response.status >= 500) {
137→			const body = await response.clone().text();
138→			logger.error("RPC error on {path}: {status} {body}", {
139→				path: url.pathname,
140→				status: response.status,
141→				body,
142→			});
143→		}
144→		for (const [key, value] of Object.entries(cors)) {
145→			response.headers.set(key, value);
146→		}
147→		return response;
148→	}
149→
150→	// Static file serving (production: frontend assets)
151→	const filePath = join(STATIC_DIR, url.pathname);
152→	const file = Bun.file(filePath);
153→	if (await file.exists()) {
154→		return new Response(file);
155→	}
156→
157→	// SPA fallback: serve index.html for non-API routes
158→	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
159→	if (await indexFile.exists()) {
160→		return new Response(indexFile);
161→	}
162→
163→	// Dev mode: redirect to frontend dev server for non-API routes
164→	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
165→	if (ALLOWED_ORIGIN !== appURL) {
166→		return Response.redirect(
167→			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
168→			302,
169→		);
170→	}
171→
172→	return new Response("Not found", { status: 404, headers: cors });
173→}
174→
175→async function getContext(request: Request) {
176→	const session = await auth.api.getSession({
177→		headers: request.headers,
178→	});
179→	return {
180→		user: session?.user ?? null,
181→		session: session?.session ?? null,
182→	};
183→}
184→
185→logger.info("API server listening on http://localhost:{port}", {
186→	port: server.port,
187→});
188→

 1→import { createORPCClient, ORPCError } from "@orpc/client";
 2→import { RPCLink } from "@orpc/client/fetch";
 3→import type { ContractRouterClient } from "@orpc/contract";
 4→import type { contract, IngestSessionInput } from "@rudel/api-routes";
 5→import type { UploadResult } from "./types.js";
 6→
 7→export interface UploadConfig {
 8→	endpoint: string;
 9→	token: string;
10→	onRetry?: (attempt: number, maxAttempts: number, error: string) => void;
11→}
12→
13→const RETRYABLE_STATUS_CODES = new Set([502, 503, 429]);
14→const MAX_ATTEMPTS = 3;
15→const BASE_DELAY_MS = 1_000;
16→
17→function isRetryable(error: unknown): boolean {
18→	if (error instanceof ORPCError) {
19→		return RETRYABLE_STATUS_CODES.has(error.status);
20→	}
21→	if (error instanceof TypeError) {
22→		return true; // network errors (fetch failures)
23→	}
24→	return false;
25→}
26→
27→function formatError(error: unknown): string {
28→	if (error instanceof ORPCError) {
29→		return `${error.status} ${error.message}`;
30→	}
31→	if (error instanceof Error) {
32→		return error.message;
33→	}
34→	return String(error);
35→}
36→
37→/**
38→ * Upload a session transcript to the backend via oRPC.
39→ * Retries on transient errors (502, 503, 429) with exponential backoff.
40→ */
41→export async function uploadSession(
42→	request: IngestSessionInput,
43→	config: UploadConfig,
44→): Promise<UploadResult> {
45→	const link = new RPCLink({
46→		url: config.endpoint,
47→		headers: {
48→			Authorization: `Bearer ${config.token}`,
49→		},
50→	});
51→
52→	const client: ContractRouterClient<typeof contract> = createORPCClient(link);
53→
54→	for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
55→		try {
56→			await client.ingestSession(request);
57→			return { success: true, status: 200, attempts: attempt };
58→		} catch (error) {
59→			const errorMessage = formatError(error);
60→
61→			if (isRetryable(error) && attempt < MAX_ATTEMPTS) {
62→				config.onRetry?.(attempt, MAX_ATTEMPTS, errorMessage);
63→				const delay = BASE_DELAY_MS * 2 ** (attempt - 1);
64→				await new Promise((resolve) => setTimeout(resolve, delay));
65→				continue;
66→			}
67→
68→			return {
69→				success: false,
70→				error: errorMessage,
71→				attempts: attempt,
72→			};
73→		}
74→	}
75→
76→	return {
77→		success: false,
78→		error: "Max retries exceeded",
79→		attempts: MAX_ATTEMPTS,
80→	};
81→}
